const body = $json.body || $json;
const message = String(body.content || '').trim();
if (!message) {
  return [];
}
return [{
  json: {
    message,
    channelId: String(body.channel_id || ''),
    username: String(body.author?.username || 'discord-user'),
    userId: String(body.author?.id || ''),
    source: 'discord-botpy'
  }
}];

const req = $('Extract Payload').item.json;
const raw = String($json.answer || $json.data?.answer || '⚠️ ระบบยังไม่พร้อมตอบ กรุณาลองใหม่');

function clip(text, max) {
  return text.length > max 
    ? text.slice(0, max - 80) + '\n\n... (ตัดข้อความ)'
    : text;
}

// clean + จัด paragraph
function format(text) {
  return text
    .replace(/```/g, '')
    .replace(/\r/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const question = String(req.message || 'ไม่มีคำถาม');
const answerRaw = format(clip(raw, 3500));
const username = String(req.username || 'ผู้ใช้');
const userId = String(req.userId || '');

const logo = 'https://img1.pic.in.th/images/roadbotailogo.png';
const iconlogo = 'https://img1.pic.in.th/images/rbaibf27db76afa900b4.png';

// 🔥 แยก intro กับเนื้อหา
let preview = answerRaw.slice(0, 300);
let full = answerRaw.slice(300);

// กันตัดคำมั่ว
if (answerRaw.length <= 300) {
  preview = answerRaw;
  full = '';
}

return [{
  json: {
    content: userId ? `<@${userId}> 🔔 มีคำตอบแล้ว` : '',
    embeds: [
      {
        color: 0x2F6FED,

        author: { 
          name: `🙋 ${username} ถามว่า`,
          icon_url: iconlogo
        },

        title: `❓ ${question}`,

        // 🔥 intro อ่านง่าย
        description: `🤖 **RoadBot AI ตอบ**\n━━━━━━━━━━━━━━━\n${preview}`,

        fields: full
          ? [
              {
                name: '📍 รายละเอียดเพิ่มเติม',
                value: full.length > 1000 ? full.slice(0, 1000) + '\n...' : full
              }
            ]
          : [],

        thumbnail: {
          url: iconlogo
        },

        image: {
          url: logo
        },

        footer: { 
          text: '🗺️ RoadBot AI • ระบบข้อมูลถนนอัจฉริยะ' 
        },

        timestamp: new Date().toISOString()
      }
    ]
  }
}];
